TEST(BitwiseDeMorgan, Case0) {
    constexpr std::array<uint_multiprecision_t, 1> a_limbs             = {{0x000000000000002AULL}};
    const big_int                                  a                   = pos_from_limbs(a_limbs);
    constexpr std::array<uint_multiprecision_t, 1> b_limbs             = {{0x000000000000000DULL}};
    const big_int                                  b                   = pos_from_limbs(b_limbs);
    constexpr std::array<uint_multiprecision_t, 1> expected_nand_limbs = {{0x0000000000000009ULL}};
    const big_int                                  expected_nand       = neg_from_limbs(expected_nand_limbs);
    constexpr std::array<uint_multiprecision_t, 1> expected_nor_limbs  = {{0x0000000000000030ULL}};
    const big_int                                  expected_nor        = neg_from_limbs(expected_nor_limbs);

    // De Morgan: ~(a & b) == ~a | ~b
    EXPECT_EQ(~(a & b), expected_nand);
    EXPECT_EQ(~a | ~b, expected_nand);
    // De Morgan: ~(a | b) == ~a & ~b
    EXPECT_EQ(~(a | b), expected_nor);
    EXPECT_EQ(~a & ~b, expected_nor);
}

